                    dp[i+1] = k+1;
                } else {
                    dp[i+1] = 2 * dp[i];
                }
            }
        } else if (s[i] == '%') {
            dp[i+1] = dp[i];
        }
    }

    if (k >= dp[n]) {
        return ".";
